// Partial loader: fetch tab partials and attach per-tab JS init if present
async function loadTabPartials() {
    const tabContents = document.querySelectorAll('.tab-content[data-partial]');
    for (const el of tabContents) {
        const partialPath = el.getAttribute('data-partial');
        if (!partialPath) continue;
        try {
            const res = await fetch(partialPath);
            if (!res.ok) { el.innerHTML = `<div style="padding:20px;color:#a00;">Failed to load ${partialPath}</div>`; continue; }
            const html = await res.text();
            el.innerHTML = html;

            // attempt to load optional per-part JS with same base name
            const jsPath = partialPath.replace(/\.html$/, '.js');
            try {
                const s = document.createElement('script');
                s.src = jsPath;
                s.defer = true;
                document.body.appendChild(s);
                s.onload = () => {
                    // call init function if exposed
                    try {
                        const initName = 'init' + (el.id ? el.id.replace(/-([a-z])/g, g => g[1].toUpperCase()).replace(/^./, c => c.toUpperCase()) : 'Tab');
                        if (window[initName] && typeof window[initName] === 'function') {
                            window[initName]();
                        }
                    } catch (err) { console.warn('init failed for', jsPath, err); }
                };
            } catch (err) {
                console.warn('No per-tab JS', jsPath, err);
            }
        } catch (err) {
            el.innerHTML = `<div style="padding:20px;color:#a00;">Error loading ${partialPath}: ${err.message}</div>`;
        }
    }
}

// load partials early
if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', () => { loadTabPartials(); initTabButtons(); });
} else {
    loadTabPartials();
    // Attach tab button handlers immediately if DOM already loaded
    initTabButtons();
}

