// TAB MANAGEMENT
function switchTab(tabName) {
    // Tüm tab button'ları pasif yap
    document.querySelectorAll('.tab-button').forEach(btn => btn.classList.remove('active'));
    
    // Tüm tab content'lerini gizle
    document.querySelectorAll('.tab-content').forEach(content => content.classList.remove('active'));
    
    // Seçilen tab button'ını aktif yap
    const tabButton = document.querySelector(`[data-tab="${tabName}"]`);
    if (tabButton) {
        tabButton.classList.add('active');
    }
    
    // Seçilen tab content'ini göster
    const tabContent = document.getElementById(`tab-${tabName}`);
    if (tabContent) {
        tabContent.classList.add('active');
        
        // Grafikler sekmesinde grafikleri render et
        if (tabName === 'charts' && allData.length > 0) {
            setTimeout(() => {
                renderCharts();
            }, 300);
        }
        
        // Export sekmesinde bilgileri güncelle
        if (tabName === 'export') {
            updateExportInfo();
        }
    }
}
        
// Tab button event listeners
function initTabButtons() {
    document.querySelectorAll('.tab-button').forEach(button => {
        button.addEventListener('click', (e) => {
            const tabName = e.target.getAttribute('data-tab');
            switchTab(tabName);
        });
    });
}

